import anthropic
from dataclasses import dataclass
from datetime import datetime
import json
import os

@dataclass
class Memory:
    content: str
    metadata: dict
    timestamp: str
    embedding: list[float] | None = None

class AgentMemoryStore:
    """
    Simple in-process memory store using cosine similarity.
    In production, replace with Pinecone, Weaviate, pgvector, etc.
    """

    def __init__(self):
        self.memories: list[Memory] = []
        self.client = anthropic.Anthropic()

    def add(self, content: str, metadata: dict = None) -> Memory:
        """Store a new memory with timestamp."""
        memory = Memory(
            content=content,
            metadata=metadata or {},
            timestamp=datetime.utcnow().isoformat()
        )
        self.memories.append(memory)
        return memory

    def search(self, query: str, top_k: int = 5) -> list[Memory]:
        """
        Find memories relevant to the query.
        Simple implementation: keyword overlap.
        Production: use embedding similarity.
        """
        query_words = set(query.lower().split())
        scored = []

        for memory in self.memories:
            memory_words = set(memory.content.lower().split())
            overlap = len(query_words & memory_words)
            if overlap > 0:
                scored.append((overlap, memory))

        scored.sort(key=lambda x: x[0], reverse=True)
        return [m for _, m in scored[:top_k]]

    def format_for_context(self, memories: list[Memory]) -> str:
        """Format memories for inclusion in agent context."""
        if not memories:
            return "No relevant memories found."

        lines = ["## Relevant memories from past sessions:"]
        for m in memories:
            lines.append(f"- [{m.timestamp[:10]}] {m.content}")
            if m.metadata:
                lines.append(f"  Context: {json.dumps(m.metadata)}")
        return "\n".join(lines)

# Tool definitions for memory-aware agent
def make_memory_tools(store: AgentMemoryStore) -> list:
    """Create tool definitions that give the agent access to memory."""
    return [
        {
            "name": "remember",
            "description": "Store a piece of information for future sessions. Use when the user shares a preference, decision, or fact that should be remembered.",
            "input_schema": {
                "type": "object",
                "properties": {
                    "content": {
                        "type": "string",
                        "description": "The information to remember"
                    },
                    "category": {
                        "type": "string",
                        "enum": ["preference", "decision", "fact", "task_context"],
                        "description": "Category of memory"
                    }
                },
                "required": ["content", "category"]
            }
        },
        {
            "name": "recall",
            "description": "Search past memories for information relevant to a query. Use when you need to know about user preferences or past decisions.",
            "input_schema": {
                "type": "object",
                "properties": {
                    "query": {
                        "type": "string",
                        "description": "What to search for in memories"
                    }
                },
                "required": ["query"]
            }
        }
    ]

# Usage
store = AgentMemoryStore()
store.add("User prefers PostgreSQL for all new projects", {"category": "preference"})
store.add("API uses snake_case for all endpoint paths", {"category": "fact"})
store.add("Decided to use JWT for auth in the payments service", {"category": "decision"})

relevant = store.search("database choice for new microservice")
print(store.format_for_context(relevant))
